def validate_cart_items(cart_items: List[CartItem]) -> Dict[str, Any]:
    if not cart_items:
        raise ValidationError("Cart is empty.")

    normalized_items = []
    subtotal = Decimal("0.00")

    for item in cart_items:
        if not item.sku or not item.name:
            raise ValidationError("Each cart item must have a SKU and name.")
        if item.quantity <= 0:
            raise ValidationError(f"Invalid quantity for item {item.sku}.")
        if _money(item.unit_price) < 0:
            raise ValidationError(f"Invalid unit price for item {item.sku}.")

        line_total = item.line_total()
        subtotal += line_total
        normalized_items.append(
            {
                "sku": item.sku,
                "name": item.name,
                "quantity": item.quantity,
                "unit_price": _money(item.unit_price),
                "line_total": _money(line_total),
            }
        )

    return {
        "items": normalized_items,
        "subtotal": _money(subtotal),
    }


def apply_discount_code(
    user: User,
    validated_cart: Dict[str, Any],
    discount_code: Optional[DiscountCode],
) -> Dict[str, Any]:
    subtotal = _money(validated_cart["subtotal"])
    discount_amount = Decimal("0.00")
    applied_code = None

    if discount_code is None:
        return {
            **validated_cart,
            "discount_code": None,
            "discount": _money(discount_amount),
            "discounted_subtotal": _money(subtotal),
        }

    if discount_code.admin_only and not user.is_admin:
        raise PermissionError(f"Discount code {discount_code.code} is admin-only.")

    if discount_code.allowed_tiers is not None and user.tier not in discount_code.allowed_tiers:
        raise PermissionError(f"Discount code {discount_code.code} is not allowed for tier {user.tier}.")

    if discount_code.kind == "percent":
        discount_amount = (subtotal * _money(discount_code.value) / Decimal("100")).quantize(
            Decimal("0.01"), rounding=ROUND_HALF_UP
        )
    elif discount_code.kind == "fixed":
        discount_amount = _money(discount_code.value)
    else:
        raise ValidationError(f"Unsupported discount type: {discount_code.kind}")

    if discount_amount < 0:
        raise ValidationError("Discount amount cannot be negative.")

    if discount_amount > subtotal:
        discount_amount = subtotal

    applied_code = discount_code.code

    discounted_subtotal = subtotal - discount_amount

    return {
        **validated_cart,
        "discount_code": applied_code,
        "discount": _money(discount_amount),
        "discounted_subtotal": _money(discounted_subtotal),
    }


def calculate_tax(
    discounted_cart: Dict[str, Any],
    tax_rate: Decimal,
) -> Dict[str, Any]:
    if tax_rate < 0:
        raise ValidationError("Tax rate cannot be negative.")

    taxable_amount = _money(discounted_cart["discounted_subtotal"])
    tax = (taxable_amount * _money(tax_rate) / Decimal("100")).quantize(
        Decimal("0.01"), rounding=ROUND_HALF_UP
    )
    total = taxable_amount + tax

    return {
        **discounted_cart,
        "tax_rate": _money(tax_rate),
        "tax": _money(tax),
        "total": _money(total),
    }


def process_payment(user: User, taxed_cart: Dict[str, Any], payment_method: Dict[str, Any]) -> Dict[str, Any]:
    if not payment_method.get("token") and not payment_method.get("payment_id"):
        raise PaymentError("Missing payment credentials.")

    total = _money(taxed_cart["total"])
    if total <= 0:
        raise PaymentError("Payment total must be greater than zero.")

    transaction_id = payment_method.get("payment_id") or f"txn_{user.id}_{abs(hash((user.id, str(total))))}"

    result = PaymentResult(
        success=True,
        transaction_id=transaction_id,
        message="Payment processed successfully.",
    )

    return {
        **taxed_cart,
        "payment_result": result,
    }


def create_order_record(user: User, paid_cart: Dict[str, Any]) -> OrderRecord:
    payment_result = paid_cart.get("payment_result")
    if not payment_result or not payment_result.success:
        raise CheckoutError("Cannot create order record without successful payment.")

    order_id = f"ord_{user.id}_{abs(hash((user.id, payment_result.transaction_id, str(paid_cart['total']))))}"

    return OrderRecord(
        order_id=order_id,
        user_id=user.id,
        items=paid_cart["items"],
        subtotal=_money(paid_cart["subtotal"]),
        discount=_money(paid_cart["discount"]),
        tax=_money(paid_cart["tax"]),
        total=_money(paid_cart["total"]),
        discount_code=paid_cart.get("discount_code"),
        payment_transaction_id=payment_result.transaction_id,
    )


def checkout(
    user: User,
    cart_items: List[CartItem],
    tax_rate: Decimal,
    payment_method: Dict[str, Any],
    discount_code: Optional[DiscountCode] = None,
) -> OrderRecord:
    validated = validate_cart_items(cart_items)
    discounted = apply_discount_code(user, validated, discount_code)
    taxed = calculate_tax(discounted, tax_rate)
    paid = process_payment(user, taxed, payment_method)
    order = create_order_record(user, paid)
    return order